{
  "$schema": "https://metaharness.dev/schemas/mcp-policy/v1.json",
  "version": "1",
  "description": "MCP policy for @metaharness/example-stripe — billing-audit harness. Default-deny; only read-only Stripe API tools are granted. Any mutation (create, update, cancel, delete) is blocked unless the --allow-mutations flag is explicitly passed at harness invocation.",

  "defaultDeny": true,
  "allowNetwork": false,
  "allowShell": false,
  "allowFileWrite": false,
  "requireApprovalForDangerous": true,
  "toolTimeoutMs": 30000,
  "maxToolCallsPerTurn": 12,

  "mutations_require_flag": "--allow-mutations",

  "audit_log": {
    "enabled": true,
    "path": ".harness/audit/stripe-audit.jsonl",
    "note": "Append-only JSONL. Never truncated by the harness. Each line: { ts, tool, args_hash, result_code, agent, run_id }."
  },

  "grants": [
    {
      "tool": "stripe_customers_retrieve",
      "reason": "Read a single customer record by ID — no mutation surface."
    },
    {
      "tool": "stripe_customers_list",
      "reason": "Paginate customer list; read-only."
    },
    {
      "tool": "stripe_subscriptions_retrieve",
      "reason": "Read a single subscription record."
    },
    {
      "tool": "stripe_subscriptions_list",
      "reason": "List subscriptions with filter params; read-only."
    },
    {
      "tool": "stripe_invoices_retrieve",
      "reason": "Read a single invoice record."
    },
    {
      "tool": "stripe_invoices_list",
      "reason": "List invoices with filter params; read-only."
    },
    {
      "tool": "stripe_invoice_items_list",
      "reason": "Read line items on an invoice; read-only."
    },
    {
      "tool": "stripe_payment_intents_retrieve",
      "reason": "Read a payment intent for reconciliation; read-only."
    },
    {
      "tool": "stripe_charges_retrieve",
      "reason": "Read a charge record; read-only."
    },
    {
      "tool": "stripe_charges_list",
      "reason": "List charges with filter params; read-only."
    },
    {
      "tool": "stripe_products_retrieve",
      "reason": "Read product metadata; read-only."
    },
    {
      "tool": "stripe_prices_retrieve",
      "reason": "Read price/plan metadata; read-only."
    },
    {
      "tool": "stripe_prices_list",
      "reason": "List prices attached to a product; read-only."
    },
    {
      "tool": "stripe_balance_retrieve",
      "reason": "Read current Stripe balance; read-only."
    },
    {
      "tool": "stripe_balance_transactions_list",
      "reason": "Paginate balance transaction history for reconciliation; read-only."
    },
    {
      "tool": "stripe_events_list",
      "reason": "Read event log for audit trail; read-only."
    },
    {
      "tool": "read_file",
      "reason": "Read local report files written by the executor agent."
    },
    {
      "tool": "write_file",
      "reason": "Write audit-report JSON/Markdown to the reports/ output directory only.",
      "path_allowlist": ["reports/**"]
    }
  ],

  "denied_unless_allow_mutations_flag": [
    "stripe_customers_create",
    "stripe_customers_update",
    "stripe_customers_delete",
    "stripe_subscriptions_create",
    "stripe_subscriptions_update",
    "stripe_subscriptions_cancel",
    "stripe_invoices_create",
    "stripe_invoices_finalize",
    "stripe_invoices_pay",
    "stripe_invoices_void",
    "stripe_refunds_create",
    "stripe_payment_intents_create",
    "stripe_payment_intents_confirm",
    "stripe_payment_intents_cancel"
  ],

  "sandbox_mode": {
    "default": true,
    "env_var": "STRIPE_API_KEY",
    "test_key_prefix": "sk_test_",
    "note": "The harness asserts at startup that STRIPE_API_KEY begins with 'sk_test_'. A live key ('sk_live_') will cause the doctor check to fail unless STRIPE_ALLOW_LIVE=true is explicitly set."
  }
}
